    expect(valid).toBe(false);
    expect(mockValidator.errors).toContain('header_missing');
  });

  it('should detect XREF', () => {
    const [valid] = mockValidator.validateXref('xref\n0 1');
    expect(valid).toBe(true);
  });

  it('should rebuild XREF from objects', () => {
    mockValidator.repairs = [];
    const xref = mockValidator.rebuildXref('1 0 obj<<>>endobj');
    expect(Object.keys(xref).length).toBe(1);
    expect(mockValidator.repairs.length).toBeGreaterThan(0);
  });

